const { Storage } = require('@google-cloud/storage');
const express = require('express');

// Initialize the client
const storage = new Storage();

// Create an HTTP Cloud Function that serves files from Cloud Storage
exports.serveFile = async (req, res) => {
  const bucketName = req.query.bucket;
  const filePath = req.query.file;

  if (!bucketName || !filePath) {
    res.status(400).send('Missing required query parameter');
    return;
  }

  try {
    // Get a reference to the file
    const file = storage.bucket(bucketName).file(filePath);

    // Check if the file exists
    await file.exists();

    // Set the response headers
    res.set("Content-Disposition", `attachment; filename="${filePath}"`);
    res.set("Content-Type", "application/octet-stream");

    // Stream the file to the client
    const readStream = file.createReadStream();
    readStream.pipe(res);
  } catch (err) {
    console.error(err);
    res.status(500).send('Error serving file');
  }
};